// // This SR latch maintains its state until a new value is applied to S or R. However, if S and R are both high, the outputs will be defined as Q = 0 and Qn = 1.
module sr_latch (  
    input wire S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (S or R) begin  
        if (S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end else if (S && R) begin  
            // Undefined state  
        end  
    end  
endmodule
